import React, { useEffect, useState } from "react";
import axios from "axios";

// AdminBookings.jsx
// Place this file at: src/components/admin/AdminBookings.jsx
// TailwindCSS is used for styling. Ensure axios is installed: `npm i axios`.

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000/api";

export default function AdminBookings() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // UI state
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");

  // pagination
  const [page, setPage] = useState(1);
  const PAGE_SIZE = 10;

  // edit modal state
  const [editing, setEditing] = useState(null); // booking being edited
  const [savingEdit, setSavingEdit] = useState(false);

  useEffect(() => {
    fetchBookings();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function fetchBookings() {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.get(`${API_BASE}/bookings/`);
      setBookings(Array.isArray(res.data) ? res.data : res.data.results || []);
    } catch (err) {
      console.error(err);
      setError("Failed to load bookings. Check the API or CORS settings.");
    } finally {
      setLoading(false);
    }
  }

  // Filtering + search applied on client-side for now
  const filtered = bookings
    .filter((b) => {
      if (!search.trim()) return true;
      const q = search.toLowerCase();
      return (
        (b.guest_name && b.guest_name.toLowerCase().includes(q)) ||
        (b.booking_id && b.booking_id.toString().includes(q)) ||
        (b.email && b.email.toLowerCase().includes(q))
      );
    })
    .filter((b) => (statusFilter === "all" ? true : b.status === statusFilter))
    .filter((b) => {
      if (!dateFrom && !dateTo) return true;
      const checkin = new Date(b.check_in);
      if (dateFrom && new Date(dateFrom) > checkin) return false;
      if (dateTo && new Date(dateTo) < checkin) return false;
      return true;
    });

  const pages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const displayed = filtered.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  // Actions
  async function updateStatus(bookingId, newStatus) {
    try {
      await axios.patch(`${API_BASE}/bookings/${bookingId}/`, { status: newStatus });
      // optimistic refresh
      setBookings((prev) => prev.map((b) => (b.id === bookingId ? { ...b, status: newStatus } : b)));
    } catch (err) {
      console.error(err);
      alert("Failed to update status");
    }
  }

  async function deleteBooking(bookingId) {
    if (!window.confirm("Delete this booking? This cannot be undone.")) return;
    try {
      await axios.delete(`${API_BASE}/bookings/${bookingId}/`);
      setBookings((prev) => prev.filter((b) => b.id !== bookingId));
    } catch (err) {
      console.error(err);
      alert("Failed to delete booking");
    }
  }

  function openEdit(booking) {
    setEditing({ ...booking });
  }

  function closeEdit() {
    setEditing(null);
  }

  async function saveEdit() {
    if (!editing) return;
    setSavingEdit(true);
    try {
      const payload = { ...editing };
      // remove readonly fields if present
      delete payload.created_at;
      await axios.put(`${API_BASE}/bookings/${editing.id}/`, payload);
      setBookings((prev) => prev.map((b) => (b.id === editing.id ? editing : b)));
      closeEdit();
    } catch (err) {
      console.error(err);
      alert("Failed to save changes");
    } finally {
      setSavingEdit(false);
    }
  }

  return (
    <div className="p-6">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-semibold">Bookings Management</h2>
        <div className="text-sm text-gray-500">Total: {bookings.length}</div>
      </div>

      <div className="bg-white rounded-lg shadow p-4 mb-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
          <input
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            placeholder="Search by name, id or email"
            className="border rounded p-2 w-full"
          />

          <select
            value={statusFilter}
            onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
            className="border rounded p-2 w-full"
          >
            <option value="all">All statuses</option>
            <option value="pending">Pending</option>
            <option value="confirmed">Confirmed</option>
            <option value="cancelled">Cancelled</option>
            <option value="completed">Completed</option>
          </select>

          <input
            type="date"
            value={dateFrom}
            onChange={(e) => { setDateFrom(e.target.value); setPage(1); }}
            className="border rounded p-2 w-full"
          />

          <input
            type="date"
            value={dateTo}
            onChange={(e) => { setDateTo(e.target.value); setPage(1); }}
            className="border rounded p-2 w-full"
          />
        </div>
      </div>

      <div className="bg-white rounded-lg shadow overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Booking ID</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Guest</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Dates</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Room</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Guests</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Payment</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-500">Status</th>
              <th className="px-4 py-2 text-right text-xs font-medium text-gray-500">Actions</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-100">
            {loading ? (
              <tr>
                <td colSpan={8} className="p-6 text-center">Loading...</td>
              </tr>
            ) : error ? (
              <tr>
                <td colSpan={8} className="p-6 text-center text-red-600">{error}</td>
              </tr>
            ) : displayed.length === 0 ? (
              <tr>
                <td colSpan={8} className="p-6 text-center text-gray-500">No bookings found.</td>
              </tr>
            ) : (
              displayed.map((b) => (
                <tr key={b.id}>
                  <td className="px-4 py-3 text-sm">{b.booking_id || b.id}</td>
                  <td className="px-4 py-3 text-sm">
                    <div className="font-medium">{b.guest_name}</div>
                    <div className="text-xs text-gray-500">{b.email}</div>
                  </td>
                  <td className="px-4 py-3 text-sm">{b.check_in} → {b.check_out}</td>
                  <td className="px-4 py-3 text-sm">{b.room_type || b.tent_type || "-"}</td>
                  <td className="px-4 py-3 text-sm">{b.num_guests || b.guests || 1}</td>
                  <td className="px-4 py-3 text-sm">{b.payment_status || "unknown"}</td>
                  <td className="px-4 py-3 text-sm">
                    <StatusPill status={b.status} />
                  </td>
                  <td className="px-4 py-3 text-sm text-right space-x-2">
                    <button
                      onClick={() => openEdit(b)}
                      className="px-2 py-1 mr-1 rounded text-sm border"
                    >
                      Edit
                    </button>

                    {b.status !== "confirmed" && (
                      <button
                        onClick={() => updateStatus(b.id, "confirmed")}
                        className="px-2 py-1 mr-1 rounded text-sm border bg-green-50"
                      >
                        Confirm
                      </button>
                    )}

                    {b.status !== "cancelled" && (
                      <button
                        onClick={() => updateStatus(b.id, "cancelled")}
                        className="px-2 py-1 mr-1 rounded text-sm border bg-yellow-50"
                      >
                        Cancel
                      </button>
                    )}

                    <button
                      onClick={() => deleteBooking(b.id)}
                      className="px-2 py-1 rounded text-sm border bg-red-50"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      <div className="flex items-center justify-between mt-4">
        <div className="text-sm text-gray-600">Showing {displayed.length} of {filtered.length} filtered</div>
        <div className="flex items-center space-x-2">
          <button
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page === 1}
            className="px-3 py-1 border rounded disabled:opacity-50"
          >
            Prev
          </button>
          <div className="text-sm px-2">{page} / {pages}</div>
          <button
            onClick={() => setPage((p) => Math.min(pages, p + 1))}
            disabled={page === pages}
            className="px-3 py-1 border rounded disabled:opacity-50"
          >
            Next
          </button>
        </div>
      </div>

      {/* Edit modal (simple) */}
      {editing && (
        <div className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg w-full max-w-2xl p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold">Edit Booking #{editing.booking_id || editing.id}</h3>
              <button onClick={closeEdit} className="text-gray-600">Close</button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <label className="block">
                <div className="text-xs text-gray-600">Guest name</div>
                <input className="border p-2 rounded w-full" value={editing.guest_name || ""} onChange={(e) => setEditing({...editing, guest_name: e.target.value})} />
              </label>

              <label className="block">
                <div className="text-xs text-gray-600">Email</div>
                <input className="border p-2 rounded w-full" value={editing.email || ""} onChange={(e) => setEditing({...editing, email: e.target.value})} />
              </label>

              <label className="block">
                <div className="text-xs text-gray-600">Check-in</div>
                <input type="date" className="border p-2 rounded w-full" value={editing.check_in || ""} onChange={(e) => setEditing({...editing, check_in: e.target.value})} />
              </label>

              <label className="block">
                <div className="text-xs text-gray-600">Check-out</div>
                <input type="date" className="border p-2 rounded w-full" value={editing.check_out || ""} onChange={(e) => setEditing({...editing, check_out: e.target.value})} />
              </label>

              <label className="block">
                <div className="text-xs text-gray-600">Number of guests</div>
                <input type="number" min={1} className="border p-2 rounded w-full" value={editing.num_guests || editing.guests || 1} onChange={(e) => setEditing({...editing, num_guests: parseInt(e.target.value || 1)})} />
              </label>

              <label className="block">
                <div className="text-xs text-gray-600">Status</div>
                <select className="border p-2 rounded w-full" value={editing.status || "pending"} onChange={(e) => setEditing({...editing, status: e.target.value})}>
                  <option value="pending">Pending</option>
                  <option value="confirmed">Confirmed</option>
                  <option value="cancelled">Cancelled</option>
                  <option value="completed">Completed</option>
                </select>
              </label>
            </div>

            <div className="flex items-center justify-end mt-6 space-x-3">
              <button onClick={closeEdit} className="px-4 py-2 border rounded">Cancel</button>
              <button onClick={saveEdit} disabled={savingEdit} className="px-4 py-2 bg-blue-600 text-white rounded">{savingEdit ? 'Saving...' : 'Save changes'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function StatusPill({ status }) {
  const map = {
    pending: "bg-yellow-100 text-yellow-800",
    confirmed: "bg-green-100 text-green-800",
    cancelled: "bg-red-100 text-red-800",
    completed: "bg-blue-100 text-blue-800",
  };
  const cls = map[status] || "bg-gray-100 text-gray-800";
  return <span className={`px-2 py-1 rounded text-xs font-medium ${cls}`}>{status || "unknown"}</span>;
}
